import{_ as e,c as t,o as i,a4 as o}from"./chunks/framework.BmdFiWrL.js";const g=JSON.parse('{"title":"Configuring OIDC Authentication","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/q10.md","filePath":"en_US/guide/q10.md","lastUpdated":1780261573000}'),n={name:"en_US/guide/q10.md"},d=o('<h1 id="configuring-oidc-authentication" tabindex="-1">Configuring OIDC Authentication <a class="header-anchor" href="#configuring-oidc-authentication" aria-label="Permalink to &quot;Configuring OIDC Authentication&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The original content of this page applied to the v0 OIDC configuration format and does not apply to v1 or later. This page is kept only to preserve old links; do not use the old fields for new third-party login setups.</p></div><p>Since v1, the Dashboard no longer uses the old <code>type: oidc</code>, <code>oidcIssuer</code>, <code>oidcScopes</code>, and related fields. Third-party login in the current version is configured through the unified OAuth2 binding structure.</p><p>If your OIDC provider supports standard OAuth2/OIDC endpoints, fill in the new structure described in <a href="/en_US/guide/q14.html">Setting Up OAuth 2.0 Binding</a>:</p><ul><li><code>client_id</code></li><li><code>client_secret</code></li><li><code>endpoint.auth_url</code></li><li><code>endpoint.token_url</code></li><li><code>scopes</code></li><li><code>user_info_url</code></li><li><code>user_id_path</code></li></ul><p>After configuring and restarting the Dashboard, log in with a local account first, bind the third-party account on the profile page, and then use the OAuth2 button on the login page.</p>',6),a=[d];function c(r,s,l,u,p,h){return i(),t("div",null,a)}const f=e(n,[["render",c]]);export{g as __pageData,f as default};
